"import os\nfrom sqlalchemy import create_engine\nfrom sqlalchemy.orm import sessionmaker\n\n# 환경변수로부터 데이터베이스 URL 획득 (기본값: 로컬 MySQL landmark_db)\nDATABASE_URL = os.getenv(\n    \"DATABASE_URL\", \n    \"mysql+pymysql://root:password@localhost:3306/landmark_db?charset=utf8mb4\"\n)\n\nengine = create_engine(\n    DATABASE_URL,\n    pool_pre_ping=True,\n    pool_size=10,\n    max_overflow=20\n)\n\nSessionLocal = sessionmaker(autocommit=False, autoflush=False, bind=engine)\n\ndef get_db():\n    \"\"\"FastAPI API 호출별 DB 세션 생명주기 관리용 제너레이터\"\"\"\n    db = SessionLocal()\n    try:\n        yield db\n    finally:\n        db.close()\n"